 61→	}
 62→	if !ed1.Binding {
 63→		t.Error("ED1 should be binding")
 64→	}
 65→
 66→	// Verify rolling plan
 67→	rolling, ok := decoded.Plans[PlanRolling]
 68→	if !ok {
 69→		t.Fatal("missing rolling plan")
 70→	}
