 87→func TestDeadlinePlanOmitEmpty(t *testing.T) {
 88→	// A plan with only deadline fields set should omit rolling fields
 89→	plan := DeadlinePlan{
 90→		Deadline:   "2026-11-01",
 91→		Confidence: "high",
 92→	}
 93→
 94→	raw, err := json.Marshal(plan)
 95→	if err != nil {
 96→		t.Fatalf("marshal: %v", err)
 97→	}
 98→
 99→	var m map[string]any
100→	if err := json.Unmarshal(raw, &m); err != nil {
101→		t.Fatalf("unmarshal to map: %v", err)
102→	}
103→
104→	// These fields should be present
105→	if _, ok := m["deadline"]; !ok {
106→		t.Error("expected deadline field in JSON")
107→	}
108→	if _, ok := m["confidence"]; !ok {
109→		t.Error("expected confidence field in JSON")
110→	}
111→
112→	// These zero-value fields should be omitted
113→	for _, key := range []string{"notification", "deposit_due", "opens", "closes", "source_url"} {
114→		if _, ok := m[key]; ok {
115→			t.Errorf("expected %q to be omitted from JSON", key)
116→		}
117→	}
118→	if _, ok := m["binding"]; ok {
119→		t.Error("expected binding (false) to be omitted from JSON")
120→	}
121→	if _, ok := m["notification_weeks"]; ok {
122→		t.Error("expected notification_weeks (0) to be omitted from JSON")
123→	}
124→}
