// Package namematch provides deterministic institution name matching.
//
// It loads all institutions and aliases from the database into in-memory maps
// and resolves input names to unit_id values via a 3-tier lookup:
//
//  1. Exact lowercase match against institution_name
//  2. Normalized match (diacritics stripped, punctuation removed, etc.)
//  3. Builtin alias overrides for common external-source name variants
//  4. DB alias match from search_base.institution_alias
//
// MatchByOPE6 and MatchByOPE8 provide direct lookups by OPE ID.
package namematch

import (
	"context"
	"fmt"
	"strings"

	"github.com/jackc/pgx/v5/pgxpool"
)

// Matcher holds in-memory lookup maps for deterministic name resolution.
type Matcher struct {
	exact      map[string]string // strings.ToLower(institution_name) → unit_id
	normalized map[string]string // Normalize(institution_name) → unit_id
	alias      map[string]string // strings.ToLower(db alias) → unit_id
	ope6       map[string]string // ope6_id → unit_id
	ope8       map[string]string // ope8_id → unit_id
}

// Load queries all institutions and aliases from the database and returns a
// ready-to-use Matcher. The pool must be connected and the schema must be
// populated.
func Load(ctx context.Context, pool *pgxpool.Pool) (*Matcher, error) {
	m := &Matcher{
		exact:      make(map[string]string),
		normalized: make(map[string]string),
		alias:      make(map[string]string),
		ope6:       make(map[string]string),
		ope8:       make(map[string]string),
	}

	if err := m.loadInstitutions(ctx, pool); err != nil {
		return nil, fmt.Errorf("namematch: load institutions: %w", err)
	}
	if err := m.loadAliases(ctx, pool); err != nil {
		return nil, fmt.Errorf("namematch: load aliases: %w", err)
	}
	return m, nil
}

func (m *Matcher) loadInstitutions(ctx context.Context, pool *pgxpool.Pool) error {
	rows, err := pool.Query(ctx,
		`SELECT unit_id, institution_name, ope6_id, ope8_id FROM search_base.institution`)
	if err != nil {
		return err
	}
	defer rows.Close()

	for rows.Next() {
		var unitID, name, ope6, ope8 string
		if err := rows.Scan(&unitID, &name, &ope6, &ope8); err != nil {
			return err
		}
		m.exact[strings.ToLower(name)] = unitID
		m.normalized[Normalize(name)] = unitID
		if ope6 != "" {
			m.ope6[ope6] = unitID
		}
		if ope8 != "" {
			m.ope8[ope8] = unitID
		}
	}
	return rows.Err()
}

func (m *Matcher) loadAliases(ctx context.Context, pool *pgxpool.Pool) error {
	rows, err := pool.Query(ctx,
		`SELECT unit_id, alias FROM search_base.institution_alias`)
	if err != nil {
		return err
	}
	defer rows.Close()

	for rows.Next() {
		var unitID, alias string
		if err := rows.Scan(&unitID, &alias); err != nil {
			return err
		}
		m.alias[strings.ToLower(alias)] = unitID
	}
	return rows.Err()
}

// Match resolves an institution name to its unit_id using a 3-tier lookup:
//  1. Exact lowercase match
//  2. Normalized match
//  3. Builtin alias (normalized input → canonical name → normalized lookup)
//  4. DB alias (lowercase)
//
// Returns ("", false) if no match is found.
func (m *Matcher) Match(name string) (unitID string, ok bool) {
	// Tier 1: exact lowercase
	lower := strings.ToLower(name)
	if uid, found := m.exact[lower]; found {
		return uid, true
	}

	// Tier 2: normalized
	nkey := Normalize(name)
	if uid, found := m.normalized[nkey]; found {
		return uid, true
	}

	// Tier 3: builtin alias → normalize canonical name → normalized lookup
	if canonical, found := builtinAliases[nkey]; found {
		if uid, found := m.normalized[Normalize(canonical)]; found {
			return uid, true
		}
	}

	// Tier 4: DB alias (lowercase)
	if uid, found := m.alias[lower]; found {
		return uid, true
	}

	return "", false
}

// MatchByOPE6 looks up an institution by its 6-digit OPE ID.
func (m *Matcher) MatchByOPE6(ope6 string) (unitID string, ok bool) {
	uid, found := m.ope6[ope6]
	return uid, found
}

// MatchByOPE8 looks up an institution by its 8-digit OPE ID.
func (m *Matcher) MatchByOPE8(ope8 string) (unitID string, ok bool) {
	uid, found := m.ope8[ope8]
	return uid, found
}

