package deadlines

import (
	"context"
	"net/http"
	"net/http/httptest"
	"os"
	"testing"
)

func loadFixture(t *testing.T, name string) []byte {
	t.Helper()
	data, err := os.ReadFile("testdata/" + name)
	if err != nil {
		t.Fatalf("read fixture %s: %v", name, err)
	}
	return data
}

func TestParseNextData(t *testing.T) {
	html := loadFixture(t, "bigfuture_harvard.html")

	bf, err := ParseNextData(html)
	if err != nil {
		t.Fatalf("ParseNextData: %v", err)
	}

	tests := []struct {
		name string
		got  string
		want string
	}{
		{"OrgID", bf.OrgID, "1251"},
		{"DICode", bf.DICode, "3434"},
		{"IPEDSId", bf.IPEDSId, "166027"},
		{"EarlyActionDate", bf.EarlyActionDate, "11/01/9999"},
		{"RegularDecisionDate", bf.RegularDecisionDate, "01/01/9999"},
		{"NotificationDate", bf.NotificationDate, "04/01/9999"},
		{"FinancialAidRegularDeadline", bf.FinancialAidRegularDeadline, "02/01/9999"},
	}
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			if tt.got != tt.want {
				t.Errorf("got %q, want %q", tt.got, tt.want)
			}
		})
	}

	if bf.EarlyDecision {
		t.Error("EarlyDecision should be false for Harvard")
	}
	if bf.EarlyDecisionDate != "" {
		t.Errorf("EarlyDecisionDate should be empty, got %q", bf.EarlyDecisionDate)
	}
	if bf.ResponseDeadline != "" {
		t.Errorf("ResponseDeadline should be empty, got %q", bf.ResponseDeadline)
	}
	if len(bf.ApplicationsAccepted) != 2 {
		t.Errorf("ApplicationsAccepted: got %d entries, want 2", len(bf.ApplicationsAccepted))
	}
}

func TestParseNextData_NoScript(t *testing.T) {
	html := []byte(`<html><body><p>No data here</p></body></html>`)
	_, err := ParseNextData(html)
	if err == nil {
		t.Fatal("expected error for missing __NEXT_DATA__")
	}
}

func TestParseNextData_InvalidJSON(t *testing.T) {
	html := []byte(`<script id="__NEXT_DATA__" type="application/json">{invalid json}</script>`)
	_, err := ParseNextData(html)
	if err == nil {
		t.Fatal("expected error for invalid JSON")
	}
}

func TestParseNextData_NoClosingTag(t *testing.T) {
	html := []byte(`<script id="__NEXT_DATA__" type="application/json">{"props":{}}`)
	_, err := ParseNextData(html)
	if err == nil {
		t.Fatal("expected error for missing closing script tag")
	}
}

func TestToDeadlineData(t *testing.T) {
	bf := &BigFutureData{
		OrgID:               "1251",
		DICode:              "3434",
		IPEDSId:             "166027",
		EarlyDecision:       false,
		EarlyActionDate:     "11/01/9999",
		RegularDecisionDate: "01/01/9999",
		NotificationDate:    "04/01/9999",
	}

	dd := ToDeadlineData(bf, 2026)

	// Early Action plan should exist.
	ea, ok := dd.Plans[PlanEarlyAction]
	if !ok {
		t.Fatal("expected early_action plan")
	}
	if ea.Deadline != "2026-11-01" {
		t.Errorf("EA deadline: got %q, want %q", ea.Deadline, "2026-11-01")
	}
	if ea.Confidence != "medium" {
		t.Errorf("EA confidence: got %q, want %q", ea.Confidence, "medium")
	}

	// Regular plan should exist with deadline and notification.
	reg, ok := dd.Plans[PlanRegular]
	if !ok {
		t.Fatal("expected regular plan")
	}
	if reg.Deadline != "2027-01-01" {
		t.Errorf("Regular deadline: got %q, want %q", reg.Deadline, "2027-01-01")
	}
	if reg.Notification != "2027-04-01" {
		t.Errorf("Regular notification: got %q, want %q", reg.Notification, "2027-04-01")
	}

	// No ED plan (Harvard uses EA, not ED).
	if _, ok := dd.Plans[PlanEarlyDecision1]; ok {
		t.Error("should not have early_decision_1 plan for Harvard")
	}

	// Top-level flags.
	if dd.HasEarlyDecision {
		t.Error("HasEarlyDecision should be false")
	}
	if !dd.HasEarlyAction {
		t.Error("HasEarlyAction should be true")
	}
	if dd.BigfutureID != "1251" {
		t.Errorf("BigfutureID: got %q, want %q", dd.BigfutureID, "1251")
	}
}

func TestToDeadlineData_WithED(t *testing.T) {
	bf := &BigFutureData{
		OrgID:               "999",
		EarlyDecision:       true,
		EarlyDecisionDate:   "11/15/9999",
		RegularDecisionDate: "01/15/9999",
	}

	dd := ToDeadlineData(bf, 2026)

	ed, ok := dd.Plans[PlanEarlyDecision1]
	if !ok {
		t.Fatal("expected early_decision_1 plan")
	}
	if ed.Deadline != "2026-11-15" {
		t.Errorf("ED deadline: got %q, want %q", ed.Deadline, "2026-11-15")
	}
	if !ed.Binding {
		t.Error("ED should be binding")
	}
	if !dd.HasEarlyDecision {
		t.Error("HasEarlyDecision should be true")
	}
}

func TestToDeadlineData_NullDates(t *testing.T) {
	bf := &BigFutureData{
		OrgID:               "1000",
		EarlyDecision:       false,
		EarlyActionDate:     "",
		RegularDecisionDate: "",
		NotificationDate:    "null",
	}

	dd := ToDeadlineData(bf, 2026)

	if len(dd.Plans) != 0 {
		t.Errorf("expected no plans for null/empty dates, got %d", len(dd.Plans))
	}
}

