	tests := []struct {
		input string
		year  int
		want  string
	}{
		{"11/01/9999", 2026, "2026-11-01"},
		{"01/15/9999", 2027, "2027-01-15"},
		{"4/1/9999", 2027, "2027-04-01"},
		{"", 2026, ""},
		{"null", 2026, ""},
		{"invalid", 2026, ""},
		{"13/01", 2026, ""},
	}
	for _, tt := range tests {
		t.Run(tt.input, func(t *testing.T) {
			got := convertDate(tt.input, tt.year)
			if got != tt.want {
				t.Errorf("convertDate(%q, %d) = %q, want %q", tt.input, tt.year, got, tt.want)
			}
		})
	}
}

func TestSlugFromName(t *testing.T) {
	tests := []struct {
		name string
		want string
	}{
		{"Harvard University", "harvard-university"},
		{"Massachusetts Institute of Technology", "massachusetts-institute-of-technology"},
		{"St. John's University", "st-johns-university"},
		{"Texas A&M University", "texas-a-m-university"},
		{"University of California--Berkeley", "university-of-california-berkeley"},
		{"SUNY at Albany", "suny-at-albany"},
		{"", ""},
	}
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			got := SlugFromName(tt.name)
			if got != tt.want {
				t.Errorf("SlugFromName(%q) = %q, want %q", tt.name, got, tt.want)
			}
		})
	}
}

