func TestBigFutureURL(t *testing.T) {
	got := BigFutureURL("harvard-university")
	want := "https://bigfuture.collegeboard.org/colleges/harvard-university"
	if got != want {
		t.Errorf("BigFutureURL: got %q, want %q", got, want)
	}
}

func TestParseNextData_FullRoundTrip(t *testing.T) {
