		t.Errorf("Regular deadline: %q", dd.Plans[PlanRegular].Deadline)
	}
	if dd.Plans[PlanRegular].Notification != "2027-04-01" {
		t.Errorf("Regular notification: %q", dd.Plans[PlanRegular].Notification)
	}
