func TestToDeadlineData(t *testing.T) {
	bf := &BigFutureData{
		OrgID:               "1251",
		DICode:              "3434",
		IPEDSId:             "166027",
		EarlyDecision:       false,
		EarlyActionDate:     "11/01/9999",
		RegularDecisionDate: "01/01/9999",
		NotificationDate:    "04/01/9999",
	}

	dd := ToDeadlineData(bf, 2026)

	// Early Action plan should exist.
	ea, ok := dd.Plans[PlanEarlyAction]
	if !ok {
		t.Fatal("expected early_action plan")
	}
	if ea.Deadline != "2026-11-01" {
		t.Errorf("EA deadline: got %q, want %q", ea.Deadline, "2026-11-01")
	}
	if ea.Confidence != "medium" {
		t.Errorf("EA confidence: got %q, want %q", ea.Confidence, "medium")
	}

	// Regular plan should exist with deadline and notification.
	reg, ok := dd.Plans[PlanRegular]
	if !ok {
		t.Fatal("expected regular plan")
	}
	if reg.Deadline != "2027-01-01" {
		t.Errorf("Regular deadline: got %q, want %q", reg.Deadline, "2027-01-01")
	}
	if reg.Notification != "2027-04-01" {
		t.Errorf("Regular notification: got %q, want %q", reg.Notification, "2027-04-01")
	}

	// No ED plan (Harvard uses EA, not ED).
	if _, ok := dd.Plans[PlanEarlyDecision1]; ok {
		t.Error("should not have early_decision_1 plan for Harvard")
	}

	// Top-level flags.
	if dd.HasEarlyDecision {
		t.Error("HasEarlyDecision should be false")
	}
	if !dd.HasEarlyAction {
		t.Error("HasEarlyAction should be true")
	}
	if dd.BigfutureID != "1251" {
		t.Errorf("BigfutureID: got %q, want %q", dd.BigfutureID, "1251")
	}
}

