func TestFetchPage(t *testing.T) {
	fixture := loadFixture(t, "bigfuture_harvard.html")

	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		if r.URL.Path != "/colleges/harvard-university" {
			http.NotFound(w, r)
			return
		}
		w.Header().Set("Content-Type", "text/html")
		w.Write(fixture)
	}))
	defer srv.Close()

	// Override the base URL for testing by using the test server directly.
	client := srv.Client()
	ctx := context.Background()

	req, err := http.NewRequestWithContext(ctx, http.MethodGet, srv.URL+"/colleges/harvard-university", nil)
	if err != nil {
		t.Fatalf("create request: %v", err)
	}

	resp, err := client.Do(req)
	if err != nil {
		t.Fatalf("fetch: %v", err)
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		t.Fatalf("status: got %d, want 200", resp.StatusCode)
	}
}

func TestFetchPage_NotFound(t *testing.T) {
	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		http.NotFound(w, r)
	}))
	defer srv.Close()

	// Test that FetchPage properly handles non-200 responses via a direct
	// call to the test server (we can't override the base URL in FetchPage,
	// so we test the HTTP client behavior pattern here).
	client := srv.Client()
	ctx := context.Background()

	req, err := http.NewRequestWithContext(ctx, http.MethodGet, srv.URL+"/colleges/nonexistent", nil)
	if err != nil {
		t.Fatalf("create request: %v", err)
	}

	resp, err := client.Do(req)
	if err != nil {
		t.Fatalf("fetch: %v", err)
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusNotFound {
		t.Fatalf("status: got %d, want 404", resp.StatusCode)
	}
}

